const words=['software engineer.','learner.','tech enthusiast.','gamer.'];let idx=0;let str='';if($('#typity').length!=0){startType(words[idx],0);}function startType(word,charIdx){if(charIdx<word.length){str+=word.charAt(charIdx);$('#typity').html(str);charIdx++;setTimeout(function(){startType(word,charIdx);},50);}else{startWipe();str='';}}function startWipe(){idx=idx<words.length-1?idx+1:0;setTimeout(function(){$('#typity').addClass('highlighted')},1000);setTimeout(function(){$('#typity').removeClass('highlighted').text('');},2000);setTimeout(function(){startType(words[idx],0);},2000);}$(".button-collapse").sideNav({closeOnClick:true,draggable:true});$('#slide-out > li > a[href*="#"]').on('click',function(){if(location.pathname=='/'){const href=$(this).attr('href').replace(/[\/]+/g,'');$('html, body').animate({scrollTop:$(href).offset().top},1000);}});